import{_ as e,c as o,o as r,a1 as i}from"./chunks/framework.DILC4Csi.js";const c=JSON.parse('{"title":"クイックスタート：オーケストレーション機能 | oh-my-opencode","description":"oh-my-opencode を素早くインストールして使い始めましょう。基本的なオーケストレーション機能と Ultrawork モードを学びます。5 分でインストールと基本設定を完了します。","frontmatter":{"title":"クイックスタート：オーケストレーション機能 | oh-my-opencode","sidebarTitle":"5 分で始める","subtitle":"クイックスタート：オーケストレーション機能","description":"oh-my-opencode を素早くインストールして使い始めましょう。基本的なオーケストレーション機能と Ultrawork モードを学びます。5 分でインストールと基本設定を完了します。","order":10},"headers":[],"relativePath":"ja/code-yeongyu/oh-my-opencode/start/index.md","filePath":"ja/code-yeongyu/oh-my-opencode/start/index.md"}'),l={name:"ja/code-yeongyu/oh-my-opencode/start/index.md"};function t(s,a,n,d,h,p){return r(),o("div",null,[...a[0]||(a[0]=[i('<h1 id="クイックスタート" tabindex="-1">クイックスタート <a class="header-anchor" href="#クイックスタート" aria-label="Permalink to &quot;クイックスタート&quot;">​</a></h1><p>このセクションでは、oh-my-opencode のインストールから使用開始までを素早く進めることができます。基本設定からメインオーケストレーター、そしてワンクリックですべての機能を有効にする Ultrawork モードまでをカバーします。</p><h2 id="学習パス" tabindex="-1">学習パス <a class="header-anchor" href="#学習パス" aria-label="Permalink to &quot;学習パス&quot;">​</a></h2><p>以下の順序で学習することで、oh-my-opencode の基本機能を段階的に習得できます：</p><h3 id="_1-クイックインストールと設定" tabindex="-1">1. <a href="./installation/">クイックインストールと設定</a> <a class="header-anchor" href="#_1-クイックインストールと設定" aria-label="Permalink to &quot;1. [クイックインストールと設定](./installation/)&quot;">​</a></h3><p>oh-my-opencode のインストール、Provider 設定、および基本検証を完了します。</p><ul><li>oh-my-opencode のインストール</li><li>AI Provider の設定（Claude、OpenAI、Gemini など）</li><li>設定が正しいか検証</li><li>設定ファイル構造の理解</li></ul><h3 id="_2-sisyphus-の紹介-メインオーケストレーター" tabindex="-1">2. <a href="./sisyphus-orchestrator/">Sisyphus の紹介：メインオーケストレーター</a> <a class="header-anchor" href="#_2-sisyphus-の紹介-メインオーケストレーター" aria-label="Permalink to &quot;2. [Sisyphus の紹介：メインオーケストレーター](./sisyphus-orchestrator/)&quot;">​</a></h3><p>エージェントオーケストレーションの核心概念を理解し、Sisyphus エージェントの基本的な使い方を学びます。</p><ul><li>エージェントオーケストレーションシステムとは</li><li>Sisyphus エージェントの核心機能</li><li>基本的な使い方とベストプラクティス</li><li>マルチモデル協調のワークフローの理解</li></ul><h3 id="_3-ultrawork-モード-ワンクリックですべての機能を有効化" tabindex="-1">3. <a href="./ultrawork-mode/">Ultrawork モード：ワンクリックですべての機能を有効化</a> <a class="header-anchor" href="#_3-ultrawork-モード-ワンクリックですべての機能を有効化" aria-label="Permalink to &quot;3. [Ultrawork モード：ワンクリックですべての機能を有効化](./ultrawork-mode/)&quot;">​</a></h3><p>ultrawork キーワードを使用して、すべての専門エージェントと並列タスク機能を素早く有効にする方法を学びます。</p><ul><li>Ultrawork モードとは</li><li>ultrawork キーワードのトリガー方法</li><li>10 人の専門エージェントの協調作業</li><li>並列バックグラウンドタスクの管理</li></ul><h2 id="前提条件" tabindex="-1">前提条件 <a class="header-anchor" href="#前提条件" aria-label="Permalink to &quot;前提条件&quot;">​</a></h2><p>このセクションを始める前に、以下を確認してください：</p><ul><li>Node.js 18+ がインストールされていること（バージョン 20 以上を推奨）</li><li>基本的なコマンドライン操作に慣れていること</li><li>少なくとも 1 つの AI サービスの API キーを持っていること（Claude、OpenAI、または Gemini）</li></ul><div class="tip custom-block"><p class="custom-block-title">キーを持っていませんか？</p><p>まだ AI サービスの API キーを持っていない場合は、Claude から申請を始めることができます。現在、最も推奨される選択肢です。</p></div><h2 id="次のステップ" tabindex="-1">次のステップ <a class="header-anchor" href="#次のステップ" aria-label="Permalink to &quot;次のステップ&quot;">​</a></h2><p>このセクションを完了したら、以下の学習を続けることができます：</p><ul><li><strong><a href="./../../platforms/provider-setup/">プラットフォームと統合</a></strong> - マルチ Provider 設定とモデル戦略の詳細</li><li><strong><a href="./../../advanced/ai-agents-overview/">高度な機能</a></strong> - 完全な 10 人のエージェントチームと高度な機能の探索</li></ul>',20)])])}const m=e(l,[["render",t]]);export{c as __pageData,m as default};
